import { View, Text, StyleSheet, ScrollView } from 'react-native';
import { useLocalSearchParams, Stack } from 'expo-router';
import { SafeAreaView } from 'react-native-safe-area-context';
import { useCachedQuery } from '@/hooks/useCachedQuery';
import { useBrightness } from '@/hooks/useBrightness';
import { supabase } from '@/lib/supabase';
import { OfferQRDisplay } from '@/components/offers/OfferQRDisplay';
import { Card } from '@/components/ui/Card';
import { Badge } from '@/components/ui/Badge';
import { SkeletonCard } from '@/components/ui/Skeleton';
import theme from '@/theme';
import type { CampaignRedemption } from '@astrolab/shared';

export default function OfferDetailScreen() {
  const { offerId } = useLocalSearchParams<{ offerId: string }>();

  useBrightness(true);

  const { data: offer, loading } = useCachedQuery<CampaignRedemption | null>(
    `offer_${offerId}`,
    async () => {
      const { data, error } = await supabase
        .from('campaign_redemptions')
        .select('*, campaigns(title, message, offer_type, offer_value, offer_description, merchants(name, logo_url))')
        .eq('id', offerId)
        .single();
      if (error) throw error;
      return data as unknown as CampaignRedemption;
    },
    [offerId]
  );

  const campaign = (offer as any)?.campaigns;
  const merchant = campaign?.merchants;
  const isExpired = offer?.expires_at ? new Date(offer.expires_at) < new Date() : false;
  const isUsed = offer?.is_redeemed ?? false;

  if (loading) {
    return (
      <SafeAreaView style={styles.container}>
        <Stack.Screen options={{ headerShown: true, title: 'Chargement...' }} />
        <View style={styles.content}><SkeletonCard /><SkeletonCard /></View>
      </SafeAreaView>
    );
  }

  if (!offer) {
    return (
      <SafeAreaView style={styles.container}>
        <Stack.Screen options={{ headerShown: true, title: 'Offre introuvable' }} />
        <View style={styles.content}>
          <Text style={styles.errorText}>Cette offre n'existe pas.</Text>
        </View>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.container} edges={['top']}>
      <Stack.Screen
        options={{
          headerShown: true,
          title: merchant?.name ?? 'Offre',
          headerStyle: { backgroundColor: theme.colors.background },
          headerTintColor: theme.colors.text,
        }}
      />
      <ScrollView contentContainerStyle={styles.content}>
        {/* QR */}
        <OfferQRDisplay
          token={offer.redemption_token}
          isUsed={isUsed}
          isExpired={isExpired}
        />

        {/* Details */}
        <Card>
          <View style={styles.detailHeader}>
            <Text style={styles.offerTitle}>{campaign?.title ?? 'Offre'}</Text>
            <Badge variant={isUsed ? 'neutral' : isExpired ? 'error' : 'success'}>
              {isUsed ? 'Utilisee' : isExpired ? 'Expiree' : 'Active'}
            </Badge>
          </View>
          <Text style={styles.offerDesc}>
            {campaign?.offer_description ?? campaign?.message ?? ''}
          </Text>

          <View style={styles.metaRow}>
            <View style={styles.metaItem}>
              <Text style={styles.metaLabel}>Commercant</Text>
              <Text style={styles.metaValue}>{merchant?.name ?? '—'}</Text>
            </View>
            {offer.expires_at && (
              <View style={styles.metaItem}>
                <Text style={styles.metaLabel}>Expire le</Text>
                <Text style={styles.metaValue}>
                  {new Date(offer.expires_at).toLocaleDateString('fr-FR')}
                </Text>
              </View>
            )}
            {offer.redeemed_at && (
              <View style={styles.metaItem}>
                <Text style={styles.metaLabel}>Utilisee le</Text>
                <Text style={styles.metaValue}>
                  {new Date(offer.redeemed_at).toLocaleDateString('fr-FR')}
                </Text>
              </View>
            )}
          </View>
        </Card>

        {/* Instructions */}
        {!isUsed && !isExpired && (
          <Card style={styles.instructionCard}>
            <Text style={styles.instructionTitle}>Comment utiliser cette offre ?</Text>
            <Text style={styles.instructionText}>
              1. Presentez le QR code ci-dessus au commercant{'\n'}
              2. Le commercant scanne le QR code{'\n'}
              3. La reduction est appliquee automatiquement
            </Text>
          </Card>
        )}
      </ScrollView>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: theme.colors.background },
  content: { padding: theme.spacing.lg, gap: theme.spacing.md, paddingBottom: 100 },
  detailHeader: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', marginBottom: theme.spacing.sm },
  offerTitle: { fontSize: theme.fontSize.lg, fontWeight: '700', color: theme.colors.text, flex: 1 },
  offerDesc: { fontSize: theme.fontSize.base, color: theme.colors.textMuted, lineHeight: 22, marginBottom: theme.spacing.md },
  metaRow: { gap: theme.spacing.sm },
  metaItem: { flexDirection: 'row', justifyContent: 'space-between', paddingVertical: theme.spacing.xs },
  metaLabel: { fontSize: theme.fontSize.sm, color: theme.colors.textMuted },
  metaValue: { fontSize: theme.fontSize.sm, fontWeight: '500', color: theme.colors.text },
  instructionCard: { backgroundColor: `${theme.colors.primary}10` },
  instructionTitle: { fontSize: theme.fontSize.base, fontWeight: '600', color: theme.colors.primary, marginBottom: theme.spacing.sm },
  instructionText: { fontSize: theme.fontSize.sm, color: theme.colors.text, lineHeight: 22 },
  errorText: { fontSize: theme.fontSize.base, color: theme.colors.textMuted, textAlign: 'center', paddingVertical: theme.spacing.xl },
});
