import { useState, useMemo } from 'react';
import { View, Text, StyleSheet, FlatList, Pressable, RefreshControl } from 'react-native';
import { useRouter } from 'expo-router';
import { SafeAreaView } from 'react-native-safe-area-context';
import { useCachedQuery } from '@/hooks/useCachedQuery';
import { supabase } from '@/lib/supabase';
import { Card } from '@/components/ui/Card';
import { Badge } from '@/components/ui/Badge';
import { EmptyState } from '@/components/ui/EmptyState';
import { SkeletonCard } from '@/components/ui/Skeleton';
import { OfflineBanner } from '@/components/ui/OfflineBanner';
import theme from '@/theme';
import type { CampaignRedemption } from '@astrolab/shared';

type Filter = 'all' | 'active' | 'used' | 'expired';

export default function OffersScreen() {
  const router = useRouter();
  const [filter, setFilter] = useState<Filter>('all');

  const { data: offers, loading, refresh } = useCachedQuery<CampaignRedemption[]>(
    'all_offers',
    async () => {
      const { data, error } = await supabase
        .from('campaign_redemptions')
        .select('*, campaigns(title, message, offer_type, offer_value, offer_description, merchants(name, logo_url))')
        .order('created_at', { ascending: false });
      if (error) throw error;
      return (data as unknown as CampaignRedemption[]) ?? [];
    },
    []
  );

  const filtered = useMemo(() => {
    if (!offers) return [];
    const now = new Date();
    return offers.filter((o) => {
      const isExpired = o.expires_at ? new Date(o.expires_at) < now : false;
      if (filter === 'active') return !o.is_redeemed && !isExpired;
      if (filter === 'used') return o.is_redeemed;
      if (filter === 'expired') return isExpired && !o.is_redeemed;
      return true;
    });
  }, [offers, filter]);

  const getStatus = (o: CampaignRedemption) => {
    if (o.is_redeemed) return { label: 'Utilisee', variant: 'neutral' as const };
    if (o.expires_at && new Date(o.expires_at) < new Date()) return { label: 'Expiree', variant: 'error' as const };
    return { label: 'Active', variant: 'success' as const };
  };

  const filters: { key: Filter; label: string }[] = [
    { key: 'all', label: 'Toutes' },
    { key: 'active', label: 'Actives' },
    { key: 'used', label: 'Utilisees' },
    { key: 'expired', label: 'Expirees' },
  ];

  return (
    <SafeAreaView style={styles.container} edges={['top']}>
      <OfflineBanner />
      <View style={styles.header}>
        <Text style={styles.title}>Mes offres</Text>
      </View>

      {/* Filters */}
      <View style={styles.filterRow}>
        {filters.map((f) => (
          <Pressable
            key={f.key}
            onPress={() => setFilter(f.key)}
            style={[styles.filterChip, filter === f.key && styles.filterChipActive]}
          >
            <Text style={[styles.filterText, filter === f.key && styles.filterTextActive]}>
              {f.label}
            </Text>
          </Pressable>
        ))}
      </View>

      {loading && !offers?.length ? (
        <View style={styles.skeletons}><SkeletonCard /><SkeletonCard /><SkeletonCard /></View>
      ) : !filtered.length ? (
        <EmptyState
          icon="🎁"
          title="Aucune offre"
          description="Vos offres promotionnelles apparaitront ici."
        />
      ) : (
        <FlatList
          data={filtered}
          keyExtractor={(item) => item.id}
          refreshControl={<RefreshControl refreshing={false} onRefresh={refresh} tintColor={theme.colors.primary} />}
          contentContainerStyle={styles.list}
          renderItem={({ item }) => {
            const campaign = (item as any).campaigns;
            const merchant = campaign?.merchants;
            const status = getStatus(item);
            return (
              <Pressable onPress={() => router.push(`/(tabs)/offers/${item.id}`)}>
                <Card style={styles.offerCard}>
                  <View style={styles.offerHeader}>
                    <View style={{ flex: 1 }}>
                      <Text style={styles.offerTitle}>{campaign?.title ?? 'Offre'}</Text>
                      <Text style={styles.merchantName}>{merchant?.name ?? ''}</Text>
                    </View>
                    <Badge variant={status.variant}>{status.label}</Badge>
                  </View>
                  <Text style={styles.offerDesc} numberOfLines={2}>
                    {campaign?.offer_description ?? campaign?.message ?? ''}
                  </Text>
                  {item.expires_at && (
                    <Text style={styles.offerExpiry}>
                      Expire le {new Date(item.expires_at).toLocaleDateString('fr-FR')}
                    </Text>
                  )}
                </Card>
              </Pressable>
            );
          }}
        />
      )}
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: theme.colors.background },
  header: { paddingHorizontal: theme.spacing.lg, paddingTop: theme.spacing.md, paddingBottom: theme.spacing.sm },
  title: { fontSize: theme.fontSize['2xl'], fontWeight: '700', color: theme.colors.text },
  filterRow: { flexDirection: 'row', paddingHorizontal: theme.spacing.lg, gap: theme.spacing.sm, marginBottom: theme.spacing.md },
  filterChip: { paddingHorizontal: theme.spacing.md, paddingVertical: theme.spacing.xs, borderRadius: theme.borderRadius.full, backgroundColor: theme.colors.surface, borderWidth: 1, borderColor: theme.colors.border },
  filterChipActive: { backgroundColor: theme.colors.primary, borderColor: theme.colors.primary },
