import { View, Text, StyleSheet } from 'react-native';
import { useLocalSearchParams, Stack, useRouter } from 'expo-router';
import { SafeAreaView } from 'react-native-safe-area-context';
import { useCachedQuery } from '@/hooks/useCachedQuery';
import { useBrightness } from '@/hooks/useBrightness';
import { useAuth } from '@/contexts/AuthContext';
import { supabase } from '@/lib/supabase';
import { OfferQRDisplay } from '@/components/offers/OfferQRDisplay';
import { Card } from '@/components/ui/Card';
import { Badge } from '@/components/ui/Badge';
import { Button } from '@/components/ui/Button';
import { SkeletonCard } from '@/components/ui/Skeleton';
import theme from '@/theme';
import type { CampaignRedemption } from '@astrolab/shared';

export default function DeepLinkOfferScreen() {
  const { token } = useLocalSearchParams<{ token: string }>();
  const { user } = useAuth();
  const router = useRouter();

  useBrightness(true);

  const { data: offer, loading } = useCachedQuery<CampaignRedemption | null>(
    `deeplink_offer_${token}`,
    async () => {
      if (!token) return null;
      const { data, error } = await supabase
        .from('campaign_redemptions')
        .select('*, campaigns(title, message, offer_type, offer_value, offer_description, merchants(name, logo_url))')
        .eq('redemption_token', token)
        .single();
      if (error) throw error;
      return data as unknown as CampaignRedemption;
    },
    [token]
  );

  const campaign = (offer as any)?.campaigns;
  const merchant = campaign?.merchants;
  const isExpired = offer?.expires_at ? new Date(offer.expires_at) < new Date() : false;
  const isUsed = offer?.is_redeemed ?? false;

  if (loading) {
    return (
      <SafeAreaView style={styles.container}>
        <Stack.Screen options={{ title: 'Offre' }} />
        <View style={styles.content}><SkeletonCard /></View>
      </SafeAreaView>
    );
  }

  if (!offer) {
    return (
      <SafeAreaView style={styles.container}>
        <Stack.Screen options={{ title: 'Offre introuvable' }} />
        <View style={styles.centered}>
          <Text style={styles.emoji}>❌</Text>
          <Text style={styles.errorTitle}>Offre introuvable</Text>
          <Text style={styles.errorText}>Cette offre n'existe pas ou a ete supprimee.</Text>
          {user && (
            <Button onPress={() => router.replace('/(tabs)')}>
              Retour a l'accueil
            </Button>
          )}
        </View>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.container}>
      <Stack.Screen options={{ title: merchant?.name ?? 'Offre' }} />
      <View style={styles.content}>
        <OfferQRDisplay
          token={offer.redemption_token}
          isUsed={isUsed}
          isExpired={isExpired}
        />

        <Card>
          <View style={styles.offerHeader}>
            <Text style={styles.offerTitle}>{campaign?.title ?? 'Offre'}</Text>
            <Badge variant={isUsed ? 'neutral' : isExpired ? 'error' : 'success'}>
              {isUsed ? 'Utilisee' : isExpired ? 'Expiree' : 'Active'}
            </Badge>
          </View>
          <Text style={styles.offerDesc}>{campaign?.offer_description ?? ''}</Text>
          <Text style={styles.merchantText}>Chez {merchant?.name ?? '—'}</Text>
        </Card>

        {user && (
          <Button variant="outline" onPress={() => router.replace('/(tabs)')}>
            Retour a l'accueil
          </Button>
        )}
      </View>
    </SafeAreaView>
  );
}

