import type { SupabaseClient } from '@supabase/supabase-js';
import type { LoyaltyCard, Scan, Reward, CampaignRedemption } from '../types';

export async function getCustomerCards(supabase: SupabaseClient): Promise<LoyaltyCard[]> {
  const { data, error } = await supabase
    .from('loyalty_cards')
    .select('*, merchants(name, logo_url, business_type, loyalty_type, stamps_required, points_per_euro, reward_threshold)')
    .order('updated_at', { ascending: false });
  if (error) throw error;
  return (data as unknown as LoyaltyCard[]) ?? [];
}

export async function getCustomerCardById(supabase: SupabaseClient, cardId: string): Promise<LoyaltyCard | null> {
  const { data, error } = await supabase
    .from('loyalty_cards')
    .select('*, merchants(name, logo_url, business_type, loyalty_type, stamps_required, points_per_euro, reward_threshold)')
    .eq('id', cardId)
    .single();
  if (error) throw error;
  return data as unknown as LoyaltyCard;
}

export async function getCustomerScans(supabase: SupabaseClient, limit = 50): Promise<Scan[]> {
  const { data, error } = await supabase
    .from('scans')
    .select('*, merchants(name)')
    .order('created_at', { ascending: false })
    .limit(limit);
  if (error) throw error;
  return (data as unknown as Scan[]) ?? [];
}

export async function getCustomerRewards(supabase: SupabaseClient, merchantId?: string): Promise<Reward[]> {
  let query = supabase
    .from('rewards')
    .select('*')
    .order('created_at', { ascending: false });

  if (merchantId) {
    query = query.eq('merchant_id', merchantId);
  }

  const { data, error } = await query;
  if (error) throw error;
  return (data as Reward[]) ?? [];
}

export async function getCustomerOffers(supabase: SupabaseClient): Promise<CampaignRedemption[]> {
  const { data, error } = await supabase
    .from('campaign_redemptions')
    .select('*, campaigns(title, message, offer_type, offer_value, offer_description, merchants(name, logo_url))')
    .order('created_at', { ascending: false });
  if (error) throw error;
  return (data as unknown as CampaignRedemption[]) ?? [];
}

export async function getOfferByToken(supabase: SupabaseClient, token: string): Promise<CampaignRedemption | null> {
  const { data, error } = await supabase
    .from('campaign_redemptions')
    .select('*, campaigns(title, message, offer_type, offer_value, offer_description, merchants(name, logo_url))')
    .eq('redemption_token', token)
    .single();
  if (error) throw error;
  return data as unknown as CampaignRedemption;
}
